import{_ as s,c as n,o as t,ag as e}from"./chunks/framework.DK1-H3E1.js";const u=JSON.parse('{"title":"六、分布式系统理论基础","description":"","frontmatter":{"order":6},"headers":[],"relativePath":"java-learning/distributed-system-theory.md","filePath":"java-learning/distributed-system-theory.md","lastUpdated":1773678396000}'),i={name:"java-learning/distributed-system-theory.md"};function l(p,a,r,o,d,h){return t(),n("div",null,a[0]||(a[0]=[e(`<h1 id="六、分布式系统理论基础" tabindex="-1">六、分布式系统理论基础 <a class="header-anchor" href="#六、分布式系统理论基础" aria-label="Permalink to &quot;六、分布式系统理论基础&quot;">​</a></h1><h2 id="_6-1-分布式系统概述" tabindex="-1">6.1 分布式系统概述 <a class="header-anchor" href="#_6-1-分布式系统概述" aria-label="Permalink to &quot;6.1 分布式系统概述&quot;">​</a></h2><p>分布式系统是指由多个通过网络通信的计算机节点组成的系统，这些节点相互协作来完成共同的目标。对用户而言，整个系统就像一个单一的计算资源。</p><h3 id="核心特征" tabindex="-1">核心特征 <a class="header-anchor" href="#核心特征" aria-label="Permalink to &quot;核心特征&quot;">​</a></h3><ul><li><strong>透明性</strong>：用户无需知道系统的分布式特性</li><li><strong>可扩展性</strong>：可以通过增加节点来提升系统能力</li><li><strong>容错性</strong>：部分节点故障不影响整体服务</li><li><strong>并发性</strong>：多个节点可以同时处理请求</li></ul><hr><h2 id="_6-2-cap-定理" tabindex="-1">6.2 CAP 定理 <a class="header-anchor" href="#_6-2-cap-定理" aria-label="Permalink to &quot;6.2 CAP 定理&quot;">​</a></h2><p>CAP 定理（Brewer&#39;s Theorem）指出，一个分布式系统最多只能同时满足以下三个特性中的两个：</p><h3 id="_1-consistency-一致性" tabindex="-1">1. Consistency（一致性） <a class="header-anchor" href="#_1-consistency-一致性" aria-label="Permalink to &quot;1. Consistency（一致性）&quot;">​</a></h3><p>所有节点在同一时间看到的数据都是相同的。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>写操作成功后，所有读操作都必须返回最新的值</span></span></code></pre></div><h3 id="_2-availability-可用性" tabindex="-1">2. Availability（可用性） <a class="header-anchor" href="#_2-availability-可用性" aria-label="Permalink to &quot;2. Availability（可用性）&quot;">​</a></h3><p>系统提供的服务一直处于可用状态，每次请求都能在合理时间内获得响应。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每个请求都能得到响应，不保证是最新数据</span></span></code></pre></div><h3 id="_3-partition-tolerance-分区容错性" tabindex="-1">3. Partition Tolerance（分区容错性） <a class="header-anchor" href="#_3-partition-tolerance-分区容错性" aria-label="Permalink to &quot;3. Partition Tolerance（分区容错性）&quot;">​</a></h3><p>当网络分区发生时（节点间通信失败），系统仍能继续运行。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>网络故障导致节点分裂，系统仍能工作</span></span></code></pre></div><h3 id="cap-三角权衡" tabindex="-1">CAP 三角权衡 <a class="header-anchor" href="#cap-三角权衡" aria-label="Permalink to &quot;CAP 三角权衡&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        C</span></span>
<span class="line"><span>       / \\</span></span>
<span class="line"><span>      /   \\</span></span>
<span class="line"><span>     /     \\</span></span>
<span class="line"><span>    A ----- P</span></span></code></pre></div><table tabindex="0"><thead><tr><th>组合</th><th>说明</th><th>典型场景</th></tr></thead><tbody><tr><td><strong>CP</strong></td><td>保证一致性和分区容错性，牺牲可用性</td><td>分布式数据库（HBase、MongoDB）</td></tr><tr><td><strong>AP</strong></td><td>保证可用性和分区容错性，牺牲一致性</td><td>缓存系统（Redis Cluster）、DNS</td></tr><tr><td><strong>CA</strong></td><td>保证一致性和可用性，无法容忍分区</td><td>单机数据库（理论上，实际不存在）</td></tr></tbody></table><h3 id="实际系统的选择" tabindex="-1">实际系统的选择 <a class="header-anchor" href="#实际系统的选择" aria-label="Permalink to &quot;实际系统的选择&quot;">​</a></h3><p>现代分布式系统通常采用<strong>最终一致性</strong>模型，在 CAP 之间做灵活权衡：</p><ul><li><strong>ZooKeeper</strong>：CP 系统，Leader 选举期间不可用</li><li><strong>Eureka</strong>：AP 系统，节点对等，始终可用</li><li><strong>Nacos</strong>：支持 CP/AP 切换</li><li><strong>Redis Cluster</strong>：AP 系统，支持最终一致性</li><li><strong>MongoDB</strong>：CP 系统（4.0 后支持更多一致性级别）</li></ul><hr><h2 id="_6-3-base-理论" tabindex="-1">6.3 BASE 理论 <a class="header-anchor" href="#_6-3-base-理论" aria-label="Permalink to &quot;6.3 BASE 理论&quot;">​</a></h2><p>BASE 理论是对 CAP 理论的延伸，强调即使无法做到强一致性（Strong Consistency），也可以采用适当的方式实现最终一致性（Eventual Consistency）。</p><h3 id="base-三要素" tabindex="-1">BASE 三要素 <a class="header-anchor" href="#base-三要素" aria-label="Permalink to &quot;BASE 三要素&quot;">​</a></h3><h4 id="_1-basically-available-基本可用" tabindex="-1">1. Basically Available（基本可用） <a class="header-anchor" href="#_1-basically-available-基本可用" aria-label="Permalink to &quot;1. Basically Available（基本可用）&quot;">​</a></h4><p>系统出现不可预知的故障时，允许损失部分可用性来满足核心功能。</p><p><strong>实现方式：</strong></p><ul><li>服务降级（返回兜底数据）</li><li>服务熔断（快速失败）</li><li>限流（拒绝部分请求）</li><li>异步处理（削峰填谷）</li></ul><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 服务降级示例</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Service</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> OrderFallbackService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> implements</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> OrderService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    @</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Override</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    public</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Order </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">createOrder</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(OrderRequest </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">request</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        // 返回兜底数据，保证基本功能</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Order.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fallbackOrder</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(request);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h4 id="_2-soft-state-软状态" tabindex="-1">2. Soft State（软状态） <a class="header-anchor" href="#_2-soft-state-软状态" aria-label="Permalink to &quot;2. Soft State（软状态）&quot;">​</a></h4><p>允许系统存在中间状态，且该中间状态不会影响系统整体可用性。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统数据库：事务提交后，数据立即对所有客户端可见</span></span>
<span class="line"><span>软状态系统：数据可以在不同节点间异步复制，存在短暂不一致窗口</span></span></code></pre></div><h4 id="_3-eventual-consistency-最终一致性" tabindex="-1">3. Eventual Consistency（最终一致性） <a class="header-anchor" href="#_3-eventual-consistency-最终一致性" aria-label="Permalink to &quot;3. Eventual Consistency（最终一致性）&quot;">​</a></h4><p>系统经过一段时间后，所有数据副本最终能达到一致状态。</p><p><strong>最终一致性的变种：</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>说明</th><th>场景</th></tr></thead><tbody><tr><td>因果一致性</td><td>有因果关系的操作保证顺序</td><td>评论回复</td></tr><tr><td>读己之所写</td><td>用户总能读到自己之前的写入</td><td>用户配置</td></tr><tr><td>会话一致性</td><td>同一会话内保证读己之所写</td><td>购物车</td></tr><tr><td>单调读一致性</td><td>不会读到更旧的数据</td><td>消息流</td></tr><tr><td>单调写一致性</td><td>写操作按顺序执行</td><td>计数器</td></tr></tbody></table><hr><h2 id="_6-4-一致性协议" tabindex="-1">6.4 一致性协议 <a class="header-anchor" href="#_6-4-一致性协议" aria-label="Permalink to &quot;6.4 一致性协议&quot;">​</a></h2><h3 id="_6-4-1-2pc-两阶段提交" tabindex="-1">6.4.1 2PC（两阶段提交） <a class="header-anchor" href="#_6-4-1-2pc-两阶段提交" aria-label="Permalink to &quot;6.4.1 2PC（两阶段提交）&quot;">​</a></h3><p>两阶段提交（Two-Phase Commit，2PC）是分布式事务的经典协议。</p><h4 id="执行流程" tabindex="-1">执行流程 <a class="header-anchor" href="#执行流程" aria-label="Permalink to &quot;执行流程&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>阶段一：准备阶段（Voting Phase）</span></span>
<span class="line"><span>┌─────────────┐</span></span>
<span class="line"><span>│  Coordinator│</span></span>
<span class="line"><span>│  (协调者)    │</span></span>
<span class="line"><span>└──────┬──────┘</span></span>
<span class="line"><span>       │ 1. 发送 Prepare 请求</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌─────────────────────────────────┐</span></span>
<span class="line"><span>│  Participant  │  Participant    │</span></span>
<span class="line"><span>│  (参与者 A)    │  (参与者 B)      │</span></span>
<span class="line"><span>└─────────────────────────────────┘</span></span>
<span class="line"><span>       │ 2. 执行事务，记录日志</span></span>
<span class="line"><span>       │ 3. 返回 Yes/No</span></span>
<span class="line"><span></span></span>
<span class="line"><span>阶段二：提交/回滚阶段（Commit Phase）</span></span>
<span class="line"><span>┌─────────────┐</span></span>
<span class="line"><span>│  Coordinator│</span></span>
<span class="line"><span>└──────┬──────┘</span></span>
<span class="line"><span>       │ 4. 根据投票结果决定 Commit/Rollback</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌─────────────────────────────────┐</span></span>
<span class="line"><span>│  Participant  │  Participant    │</span></span>
<span class="line"><span>│  (参与者 A)    │  (参与者 B)      │</span></span>
<span class="line"><span>└─────────────────────────────────┘</span></span>
<span class="line"><span>       │ 5. 执行并提交/回滚</span></span>
<span class="line"><span>       │ 6. 返回 ACK</span></span></code></pre></div><h4 id="_2pc-的缺点" tabindex="-1">2PC 的缺点 <a class="header-anchor" href="#_2pc-的缺点" aria-label="Permalink to &quot;2PC 的缺点&quot;">​</a></h4><ol><li><strong>同步阻塞</strong>：所有参与者锁定资源等待协调者决策</li><li><strong>单点故障</strong>：协调者宕机导致整个事务挂起</li><li><strong>脑裂问题</strong>：网络分区可能导致数据不一致</li><li><strong>性能瓶颈</strong>：两阶段同步，延迟较高</li></ol><h3 id="_6-4-2-3pc-三阶段提交" tabindex="-1">6.4.2 3PC（三阶段提交） <a class="header-anchor" href="#_6-4-2-3pc-三阶段提交" aria-label="Permalink to &quot;6.4.2 3PC（三阶段提交）&quot;">​</a></h3><p>三阶段提交（Three-Phase Commit，3PC）在 2PC 基础上增加了预提交阶段。</p><h4 id="执行流程-1" tabindex="-1">执行流程 <a class="header-anchor" href="#执行流程-1" aria-label="Permalink to &quot;执行流程&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>阶段一：CanCommit（询问阶段）</span></span>
<span class="line"><span>┌─────────────┐      ┌─────────────┐</span></span>
<span class="line"><span>│ Coordinator│ ───► │ Participant │</span></span>
<span class="line"><span>│            │ ◄─── │             │</span></span>
<span class="line"><span>└─────────────┘      └─────────────┘</span></span>
<span class="line"><span>     询问是否可以提交          返回 Yes/No</span></span>
<span class="line"><span></span></span>
<span class="line"><span>阶段二：PreCommit（预提交阶段）</span></span>
<span class="line"><span>┌─────────────┐      ┌─────────────┐</span></span>
<span class="line"><span>│ Coordinator│ ───► │ Participant │</span></span>
<span class="line"><span>│            │ ◄─── │             │</span></span>
<span class="line"><span>└─────────────┘      └─────────────┘</span></span>
<span class="line"><span>     发送预提交请求        执行并返回 ACK</span></span>
<span class="line"><span></span></span>
<span class="line"><span>阶段三：DoCommit（提交阶段）</span></span>
<span class="line"><span>┌─────────────┐      ┌─────────────┐</span></span>
<span class="line"><span>│ Coordinator│ ───► │ Participant │</span></span>
<span class="line"><span>│            │ ◄─── │             │</span></span>
<span class="line"><span>└─────────────┘      └─────────────┘</span></span>
<span class="line"><span>     发送正式提交请求        提交并返回 ACK</span></span></code></pre></div><h4 id="_3pc-的改进" tabindex="-1">3PC 的改进 <a class="header-anchor" href="#_3pc-的改进" aria-label="Permalink to &quot;3PC 的改进&quot;">​</a></h4><ul><li><strong>降低阻塞</strong>：引入超时机制，超时自动回滚</li><li><strong>减少单点影响</strong>：参与者在超时情况下可以自主决策</li></ul><h4 id="_3pc-的问题" tabindex="-1">3PC 的问题 <a class="header-anchor" href="#_3pc-的问题" aria-label="Permalink to &quot;3PC 的问题&quot;">​</a></h4><ul><li>在网络分区场景下仍可能导致数据不一致</li><li>实现复杂度高，实际应用较少</li></ul><h3 id="_6-4-3-paxos-算法" tabindex="-1">6.4.3 Paxos 算法 <a class="header-anchor" href="#_6-4-3-paxos-算法" aria-label="Permalink to &quot;6.4.3 Paxos 算法&quot;">​</a></h3><p>Paxos 是一种基于消息传递的分布式一致性算法，由 Leslie Lamport 提出。</p><h4 id="核心角色" tabindex="-1">核心角色 <a class="header-anchor" href="#核心角色" aria-label="Permalink to &quot;核心角色&quot;">​</a></h4><table tabindex="0"><thead><tr><th>角色</th><th>职责</th></tr></thead><tbody><tr><td>Proposer（提议者）</td><td>提出提案（Proposal）</td></tr><tr><td>Acceptor（接受者）</td><td>对提案进行投票</td></tr><tr><td>Learner（学习者）</td><td>学习被批准的提案</td></tr></tbody></table><h4 id="两阶段协议" tabindex="-1">两阶段协议 <a class="header-anchor" href="#两阶段协议" aria-label="Permalink to &quot;两阶段协议&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>阶段一：Prepare 阶段</span></span>
<span class="line"><span>Proposer                Acceptor</span></span>
<span class="line"><span>   │                       │</span></span>
<span class="line"><span>   │─── Prepare(N) ───────►│</span></span>
<span class="line"><span>   │                       │ 若 N &gt; maxProposalId</span></span>
<span class="line"><span>   │◄─── Promise(N) ───────│ 则返回 Promise</span></span>
<span class="line"><span>   │                       │</span></span>
<span class="line"><span></span></span>
<span class="line"><span>阶段二：Accept 阶段</span></span>
<span class="line"><span>Proposer                Acceptor</span></span>
<span class="line"><span>   │                       │</span></span>
<span class="line"><span>   │── Accept(N, V) ──────►│</span></span>
<span class="line"><span>   │                       │ 若未拒绝</span></span>
<span class="line"><span>   │◄── Accepted(N) ───────│ 则接受并广播</span></span>
<span class="line"><span>   │                       │</span></span></code></pre></div><h4 id="paxos-的特点" tabindex="-1">Paxos 的特点 <a class="header-anchor" href="#paxos-的特点" aria-label="Permalink to &quot;Paxos 的特点&quot;">​</a></h4><ul><li><strong>强一致性</strong>：保证只有一个提案被批准</li><li><strong>活锁问题</strong>：多个 Proposer 可能导致无法进展</li><li><strong>实际变体</strong>：Multi-Paxos、Fast Paxos</li></ul><h3 id="_6-4-4-raft-算法" tabindex="-1">6.4.4 Raft 算法 <a class="header-anchor" href="#_6-4-4-raft-算法" aria-label="Permalink to &quot;6.4.4 Raft 算法&quot;">​</a></h3><p>Raft 是一种易于理解的分布式一致性算法，用于管理复制状态机。</p><h4 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h4><p><strong>节点状态：</strong></p><ul><li><strong>Leader</strong>：处理所有客户端请求，复制日志给 Follower</li><li><strong>Follower</strong>：接收 Leader 的心跳和日志复制</li><li><strong>Candidate</strong>：Leader 选举时的临时状态</li></ul><h4 id="节点状态转换" tabindex="-1">节点状态转换 <a class="header-anchor" href="#节点状态转换" aria-label="Permalink to &quot;节点状态转换&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    ┌─────────────┐</span></span>
<span class="line"><span>                    │   Follower  │</span></span>
<span class="line"><span>                    └──────┬──────┘</span></span>
<span class="line"><span>                           │ 选举超时</span></span>
<span class="line"><span>                           ▼</span></span>
<span class="line"><span>                    ┌─────────────┐</span></span>
<span class="line"><span>         选举失败   │  Candidate  │</span></span>
<span class="line"><span>        ◄──────────┤             │</span></span>
<span class="line"><span>                    │             │─── 获得多数票 ───► ┌─────────────┐</span></span>
<span class="line"><span>                    └─────────────┘                    │    Leader   │</span></span>
<span class="line"><span>                           │                           └─────────────┘</span></span>
<span class="line"><span>                           │ 发现更高任期的 Leader</span></span>
<span class="line"><span>                           ▼</span></span>
<span class="line"><span>                    ┌─────────────┐</span></span>
<span class="line"><span>                    │   Follower  │</span></span>
<span class="line"><span>                    └─────────────┘</span></span></code></pre></div><h4 id="raft-的工作流程" tabindex="-1">Raft 的工作流程 <a class="header-anchor" href="#raft-的工作流程" aria-label="Permalink to &quot;Raft 的工作流程&quot;">​</a></h4><ol><li><p><strong>Leader 选举</strong></p><ul><li>Follower 在选举超时后成为 Candidate</li><li>Candidate 请求其他节点投票</li><li>获得多数票的成为 Leader</li></ul></li><li><p><strong>日志复制</strong></p><ul><li>Leader 接收客户端请求</li><li>将日志复制给 Follower</li><li>多数节点确认后提交</li></ul></li><li><p><strong>安全性保证</strong></p><ul><li>只有包含最新日志的节点才能成为 Leader</li><li>日志只能由 Leader 追加</li></ul></li></ol><h4 id="raft-vs-paxos" tabindex="-1">Raft vs Paxos <a class="header-anchor" href="#raft-vs-paxos" aria-label="Permalink to &quot;Raft vs Paxos&quot;">​</a></h4><table tabindex="0"><thead><tr><th>对比项</th><th>Paxos</th><th>Raft</th></tr></thead><tbody><tr><td>理解难度</td><td>高</td><td>低</td></tr><tr><td>角色</td><td>单一</td><td>Leader/Follower/Candidate</td></tr><tr><td>日志复制</td><td>灵活</td><td>强制从 Leader 到 Follower</td></tr><tr><td>应用</td><td>理论基础</td><td>etcd、Consul、TiDB</td></tr></tbody></table><hr><h2 id="_6-5-实践建议" tabindex="-1">6.5 实践建议 <a class="header-anchor" href="#_6-5-实践建议" aria-label="Permalink to &quot;6.5 实践建议&quot;">​</a></h2><h3 id="技术选型考虑" tabindex="-1">技术选型考虑 <a class="header-anchor" href="#技术选型考虑" aria-label="Permalink to &quot;技术选型考虑&quot;">​</a></h3><ol><li><p><strong>一致性要求</strong></p><ul><li>强一致：金融交易、库存扣减 → 选 CP 系统</li><li>最终一致：社交 feed、缓存 → 选 AP 系统</li></ul></li><li><p><strong>可用性要求</strong></p><ul><li>99.9% → 允许短暂不一致</li><li>99.99%+ → 需要多活架构</li></ul></li><li><p><strong>扩展性要求</strong></p><ul><li>读多写少 → 读写分离、缓存</li><li>写多读少 → 分库分表、队列削峰</li></ul></li></ol><h3 id="常见问题及解决方案" tabindex="-1">常见问题及解决方案 <a class="header-anchor" href="#常见问题及解决方案" aria-label="Permalink to &quot;常见问题及解决方案&quot;">​</a></h3><table tabindex="0"><thead><tr><th>问题</th><th>解决方案</th></tr></thead><tbody><tr><td>分布式事务</td><td>TCC、Saga、本地消息表</td></tr><tr><td>分布式锁</td><td>Redis、ZooKeeper、数据库</td></tr><tr><td>数据一致性</td><td>对账系统、补偿机制</td></tr><tr><td>服务雪崩</td><td>熔断、降级、限流</td></tr></tbody></table><hr><p><strong>下一章</strong>：<a href="/java-learning/distributed-components.html">分布式组件 →</a></p>`,82)]))}const b=s(i,[["render",l]]);export{u as __pageData,b as default};
